__kernel void dynproc_kernel(
    const int iteration,
    __global const int* gpuWall,
    __global int* gpuSrc,
    __global int* gpuDst,
    const int cols,
    const int rows,
    const int startStep,
    const int border,
    const int HALO,
    __local int* prev,
    __local int* result,
    __global int* outputBuffer)
{
    (void)rows;
    (void)border;
    (void)HALO;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    if (get_group_id(0) != 0) return;

    const int lid = (int)get_local_id(0);
    const int lsize = (int)get_local_size(0);

    __global int* src = gpuSrc;
    __global int* dst = gpuDst;

    for (int i = 0; i < iteration; i++) {
        const int wallRow = startStep + i;
        const int wallBase = wallRow * cols;

        for (int n = lid; n < cols; n += lsize) {
            int m = src[n];
            if (n > 0) {
                int v = src[n - 1];
                if (v < m) m = v;
            }
            if (n < cols - 1) {
                int v = src[n + 1];
                if (v < m) m = v;
            }
            dst[n] = gpuWall[wallBase + n] + m;
        }

        barrier(CLK_GLOBAL_MEM_FENCE);

        __global int* tmp = src;
        src = dst;
        dst = tmp;

        barrier(CLK_GLOBAL_MEM_FENCE);
    }

    if ((iteration & 1) == 0) {
        for (int n = lid; n < cols; n += lsize) {
            gpuDst[n] = src[n];
        }
    }
}
